# api.py
import uuid, json
from fastapi import FastAPI
from pydantic import BaseModel
import redis
from celery_app import run_agent_task

app = FastAPI()
_redis = redis.Redis.from_url("redis://localhost:6379/2")

class AgentRequest(BaseModel):
    prompt: str
    model: str = "claude-haiku-4-5-20251001"
    idempotency_key: str | None = None

@app.post("/tasks")
def create_task(req: AgentRequest):
    task_id = str(uuid.uuid4())
    run_agent_task.apply_async(
        args=[task_id, req.prompt, req.model, req.idempotency_key],
        task_id=task_id,
    )
    return {"task_id": task_id, "status": "queued"}

@app.get("/tasks/{task_id}")
def get_task(task_id: str):
    raw = _redis.get(f"result:{task_id}")
    if raw is None:
        return {"task_id": task_id, "status": "pending"}
    return {"task_id": task_id} | json.loads(raw)

// worker.ts
import { Worker, Queue } from 'bullmq';
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();
const resultQueue = new Queue('results', { connection: { host: 'localhost', port: 6379 } });

const worker = new Worker('agent-tasks', async (job) => {
  const { taskId, prompt, model = 'claude-haiku-4-5-20251001' } = job.data;
  const message = await client.messages.create({
    model,
    max_tokens: 2048,
    messages: [{ role: 'user', content: prompt }],
  });
  return {
    status: 'completed',
    text: message.content[0].type === 'text' ? message.content[0].text : '',
    usage: message.usage,
  };
}, {
  connection: { host: 'localhost', port: 6379 },
  concurrency: 5,   // 5 concurrent Claude calls per worker process
});

worker.on('failed', (job, err) => {
  console.error(`Job ${job?.id} failed:`, err.message);
});

